import React from 'react';

export default function Controls({
  shirtColor,
  setShirtColor,
  backgroundColor,
  setBackgroundColor,
  autoRotate,
  setAutoRotate,
  selectedSize,
  setSelectedSize,
  activeLogoSide,
  setActiveLogoSide,
  logoSettings,
  setLogoSettings,
  logoCount,
  hasFrontLogo,
  hasBackLogo,
}) {
  const colorOptions = [
    { name: 'White', value: '#ffffff' },
    { name: 'Black', value: '#1a1a1a' },
    { name: 'Navy', value: '#1e3a5f' },
    { name: 'Red', value: '#dc2626' },
    { name: 'Forest Green', value: '#16a34a' },
    { name: 'Charcoal', value: '#6b7280' },
    { name: 'Olive', value: '#6b7547' },
    { name: 'Burgundy', value: '#7c2d3a' },
  ];

  const backgroundOptions = [
    { name: 'Black', value: '#000000' },
    { name: 'Cream', value: '#f4efe6' },
    { name: 'Sky', value: '#d7ebff' },
    { name: 'Slate', value: '#243447' },
    { name: 'Sand', value: '#d9c5a1' },
    { name: 'Mint', value: '#d8f3dc' },
  ];

  const sizes = ['XS', 'S', 'M', 'L', 'XL', 'XXL'];

  const currentLogoSettings = logoSettings[activeLogoSide];
  const hasActiveLogo = activeLogoSide === 'front' ? hasFrontLogo : hasBackLogo;

  const handlePositionChange = (axis, value) => {
    const parsedValue = parseFloat(value);
    if (Number.isNaN(parsedValue)) return;

    setLogoSettings((prev) => ({
      ...prev,
      [activeLogoSide]: {
        ...prev[activeLogoSide],
        position: {
          ...prev[activeLogoSide].position,
          [axis]: parsedValue,
        },
      },
    }));
  };

  const handleScaleChange = (value) => {
    const parsedValue = parseFloat(value);
    if (Number.isNaN(parsedValue)) return;

    setLogoSettings((prev) => ({
      ...prev,
      [activeLogoSide]: {
        ...prev[activeLogoSide],
        scale: parsedValue,
      },
    }));
  };

  const handleRotationChange = (value) => {
    const parsedValue = parseFloat(value);
    if (Number.isNaN(parsedValue)) return;

    setLogoSettings((prev) => ({
      ...prev,
      [activeLogoSide]: {
        ...prev[activeLogoSide],
        rotation: parsedValue,
      },
    }));
  };

  const resetActiveLogo = () => {
    setLogoSettings((prev) => ({
      ...prev,
      [activeLogoSide]: {
        position: {
          x: 0.015230818837193738,
          y: 1.4088348413144813,
          z: activeLogoSide === 'front' ? 0.11 : -0.11,
        },
        scale: 0.35,
        rotation: 0,
      },
    }));
  };

  const renderPositionField = (axis, label, min, max, step) => (
    <div className="position-field" key={axis}>
      <label>
        {label}: {currentLogoSettings.position[axis].toFixed(2)}
      </label>
      <div className="position-input-row">
        <input
          type="range"
          min={min}
          max={max}
          step={step}
          value={currentLogoSettings.position[axis]}
          onChange={(e) => handlePositionChange(axis, e.target.value)}
        />
        <input
          type="number"
          min={min}
          max={max}
          step={step}
          value={currentLogoSettings.position[axis]}
          onChange={(e) => handlePositionChange(axis, e.target.value)}
        />
      </div>
    </div>
  );

  return (
    <div className="controls-panel">
      {/* Color Selection */}
      <div className="control-section">
        <h3>Shirt Color</h3>
        <div className="color-grid">
          {colorOptions.map((option) => (
            <button
              key={option.value}
              className={`color-option ${shirtColor === option.value ? 'selected' : ''}`}
              style={{ backgroundColor: option.value }}
              onClick={() => setShirtColor(option.value)}
              title={option.name}
            />
          ))}
        </div>
      </div>

      <div className="control-section">
        <h3>Background Color</h3>
        <div className="color-grid">
          {backgroundOptions.map((option) => (
            <button
              key={option.value}
              className={`color-option ${backgroundColor === option.value ? 'selected' : ''}`}
              style={{ backgroundColor: option.value }}
              onClick={() => setBackgroundColor(option.value)}
              title={option.name}
            />
          ))}
        </div>
      </div>

      {/* Size Selection */}
      <div className="control-section">
        <h3>Size</h3>
        <div className="size-selector">
          {sizes.map((size) => (
            <button
              key={size}
              className={`size-btn ${selectedSize === size ? 'selected' : ''}`}
              onClick={() => setSelectedSize(size)}
            >
              {size}
            </button>
          ))}
        </div>
      </div>

      {/* Auto Rotate */}
      <div className="control-section">
        <label className="toggle-control">
          <input
            type="checkbox"
            checked={autoRotate}
            onChange={(e) => setAutoRotate(e.target.checked)}
          />
          <span>Auto Rotate</span>
        </label>
      </div>

      <div className="control-section">
        <div className="logo-summary-row">
          <h3>Logo Setup</h3>
          <span className="logo-count">{logoCount} logo{logoCount === 1 ? '' : 's'}</span>
        </div>
        <div className="logo-side-selector">
          <button
            type="button"
            className={`side-btn ${activeLogoSide === 'front' ? 'selected' : ''}`}
            onClick={() => setActiveLogoSide('front')}
          >
            Front {hasFrontLogo ? '(1)' : '(0)'}
          </button>
          <button
            type="button"
            className={`side-btn ${activeLogoSide === 'back' ? 'selected' : ''}`}
            onClick={() => setActiveLogoSide('back')}
          >
            Back {hasBackLogo ? '(1)' : '(0)'}
          </button>
        </div>
      </div>

      {/* Logo Position Controls */}
      {hasActiveLogo && (
        <div className="control-section logo-controls-section">
          <h3>{activeLogoSide.toUpperCase()} LOGO POSITION</h3>

          {renderPositionField('x', 'X Position', -0.45, 0.45, 0.01)}
          {renderPositionField('y', 'Y Position', 0.4, 3.8, 0.01)}
          {renderPositionField('z', 'Z Position', activeLogoSide === 'front' ? 0.07 : -0.18, activeLogoSide === 'front' ? 0.18 : -0.07, 0.01)}

          <div className="position-field">
            <label>Logo Size: {currentLogoSettings.scale.toFixed(2)}</label>
            <div className="position-input-row">
              <input
                type="range"
                min="0.05"
                max="0.5"
                step="0.01"
                value={currentLogoSettings.scale}
                onChange={(e) => handleScaleChange(e.target.value)}
              />
              <input
                type="number"
                min="0.05"
                max="0.5"
                step="0.01"
                value={currentLogoSettings.scale}
                onChange={(e) => handleScaleChange(e.target.value)}
              />
            </div>
          </div>

          <div className="position-field">
            <label>Rotation: {(currentLogoSettings.rotation * (180 / Math.PI)).toFixed(0)}°</label>
            <div className="position-input-row">
              <input
                type="range"
                min={-Math.PI}
                max={Math.PI}
                step="0.1"
                value={currentLogoSettings.rotation}
                onChange={(e) => handleRotationChange(e.target.value)}
              />
              <input
                type="number"
                min={-3.14}
                max={3.14}
                step="0.01"
                value={currentLogoSettings.rotation}
                onChange={(e) => handleRotationChange(e.target.value)}
              />
            </div>
          </div>

          <button 
            className="reset-btn"
            onClick={resetActiveLogo}
          >
            Reset Logo Position
          </button>
        </div>
      )}
    </div>
  );
}