import React from 'react';

export default function LogoUploader({ title, setLogo, currentLogo, onFileSelected }) {
  const handleUpload = (event) => {
    const file = event.target.files[0];
    if (!file) return;
    // Reset input so the same file can be re-selected after editing
    event.target.value = '';
    if (file.type.startsWith('image/')) {
      if (onFileSelected) {
        // Delegate to parent — parent will show the ImageProcessor modal
        onFileSelected(file);
      } else {
        // Fallback: load directly
        if (currentLogo && currentLogo.startsWith('blob:')) URL.revokeObjectURL(currentLogo);
        setLogo(URL.createObjectURL(file));
      }
    }
  };

  const loadDefaultLogo = () => {
    if (currentLogo && currentLogo.startsWith('blob:')) {
      URL.revokeObjectURL(currentLogo);
    }
    setLogo('/logo.png');
  };

  const removeLogo = () => {
    if (currentLogo && currentLogo.startsWith('blob:')) {
      URL.revokeObjectURL(currentLogo);
    }
    setLogo(null);
  };

  return (
    <div className="logo-uploader-section">
      <h3>{title}</h3>
      <div className="logo-controls">
        <label className="upload-btn">
          <input
            type="file"
            accept="image/png,image/jpg,image/jpeg,image/svg+xml"
            onChange={handleUpload}
            style={{ display: 'none' }}
          />
          <span aria-hidden="true" style={{ display: 'inline-flex', marginRight: '6px', verticalAlign: 'middle' }}>
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" />
              <polyline points="7 10 12 15 17 10" />
              <line x1="12" y1="15" x2="12" y2="3" />
            </svg>
          </span>
          Upload Logo
        </label>
        
        <button onClick={loadDefaultLogo} className="default-logo-btn">
          <span aria-hidden="true" style={{ display: 'inline-flex', marginRight: '6px', verticalAlign: 'middle' }}>
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <circle cx="13.5" cy="6.5" r=".5" fill="currentColor" />
              <circle cx="17.5" cy="10.5" r=".5" fill="currentColor" />
              <circle cx="8.5" cy="7.5" r=".5" fill="currentColor" />
              <circle cx="6.5" cy="12" r=".5" fill="currentColor" />
              <path d="M12 2C6.5 2 2 6.5 2 12s4.5 10 10 10c.926 0 1.648-.746 1.648-1.688 0-.437-.18-.835-.437-1.125-.29-.289-.438-.652-.438-1.125a1.64 1.64 0 0 1 1.668-1.668h1.996c3.051 0 5.555-2.503 5.555-5.554C21.965 6.012 17.461 2 12 2z" />
            </svg>
          </span>
          Use Default Logo
        </button>
        
        {currentLogo && (
          <button onClick={removeLogo} className="remove-logo-btn">
            <span aria-hidden="true" style={{ display: 'inline-flex', marginRight: '6px', verticalAlign: 'middle' }}>
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <line x1="18" y1="6" x2="6" y2="18" />
                <line x1="6" y1="6" x2="18" y2="18" />
              </svg>
            </span>
            Remove Logo
          </button>
        )}
      </div>
      
      {currentLogo && (
        <div className="logo-preview">
          <p>Current Logo:</p>
          <img src={currentLogo} alt="Logo preview" style={{ maxWidth: '100px', maxHeight: '100px' }} />
        </div>
      )}
    </div>
  );
}
