import React from 'react';

const PRODUCTS = [
  {
    id: 'atelier-tee-no01',
    name: 'Atelier Tee No. 01',
    price: 45,
    tagline: 'Core branded cotton tee',
    description: 'Clean premium tee ready for front and back branding with a relaxed retail fit.',
    color: '#f6efe4',
    accent: '#18130d',
    featured: true,
  },
  {
    id: 'studio-heavyweight',
    name: 'Studio Heavyweight',
    price: 58,
    tagline: 'Structured heavyweight shirt',
    description: 'Built for bolder chest marks, denser fabric feel, and elevated retail presentation.',
    color: '#c7d0d8',
    accent: '#263442',
  },
  {
    id: 'night-shift-crew',
    name: 'Night Shift Crew',
    price: 64,
    tagline: 'Dark premium street uniform',
    description: 'A darker base for monochrome branding, event teams, and lifestyle drops.',
    color: '#2a2a2d',
    accent: '#f7f1e8',
  },
  {
    id: 'capsule-starter-pack',
    name: 'Capsule Starter Pack',
    price: 120,
    tagline: 'Three-piece launch set',
    description: 'A small apparel set for launch teams that want matching looks across multiple wearers.',
    color: '#d5c2a8',
    accent: '#3b2717',
  },
  {
    id: 'retail-sample-box',
    name: 'Retail Sample Box',
    price: 85,
    tagline: 'Printed inserts and sample tee',
    description: 'A hybrid print-and-apparel package for pitch decks, retail handoff, and sample runs.',
    color: '#d9dde3',
    accent: '#263442',
  },
  {
    id: 'event-merch-bundle',
    name: 'Event Merch Bundle',
    price: 150,
    tagline: 'Fast-turn team package',
    description: 'An event-ready apparel package designed for promo teams, activations, and launches.',
    color: '#eed9c5',
    accent: '#5b3a20',
  },
];

const MARQUEE_TOP = ['Volumetric Apparel', 'YB Printing Co.', 'Flagship Collection', 'Built to Print', 'Ready to Sell'];
const MARQUEE_BOTTOM = ['Hover the collection', 'Open the builder', 'Add to cart', 'Launch your branded drop'];

function MarqueeRow({ items }) {
  return (
    <div className="collection-marquee-row">
      <div className="collection-marquee-track">
        {[...items, ...items].map((item, index) => (
          <span key={`${item}-${index}`}>{item}</span>
        ))}
      </div>
    </div>
  );
}

function ProductCard({ product, onAddToCart, onOpenCustomizer }) {
  return (
    <article className="collection-card">
      <div className="collection-card-visual" style={{ background: product.color }}>
        <div className="collection-shirt-silhouette" style={{ color: product.accent }}>
          <div className="collection-shirt-mark">YB</div>
        </div>
      </div>
      <div className="collection-card-body">
        <p className="collection-card-tag">{product.tagline}</p>
        <div className="collection-card-header">
          <h3>{product.name}</h3>
          <span>${product.price}</span>
        </div>
        <p className="collection-card-copy">{product.description}</p>
        <div className="collection-card-actions">
          <button type="button" className="collection-primary-btn" onClick={() => onAddToCart(product)}>
            Add to cart
          </button>
          <button type="button" className="collection-secondary-btn" onClick={onOpenCustomizer}>
            Customize
          </button>
        </div>
      </div>
    </article>
  );
}

function CartDrawer({ open, items, onClose, onQty, onRemove }) {
  const total = items.reduce((sum, item) => sum + (item.price * item.qty), 0);

  return (
    <>
      <div className={`cart-backdrop ${open ? 'open' : ''}`} onClick={onClose} />
      <aside className={`cart-drawer ${open ? 'open' : ''}`} aria-hidden={!open}>
        <div className="cart-drawer-header">
          <h3>Cart</h3>
          <button type="button" className="cart-close-btn" onClick={onClose}>Close</button>
        </div>
        <div className="cart-drawer-body">
          {items.length === 0 ? (
            <p className="cart-empty-copy">Your cart is empty. Add collection pieces or a custom shirt to start the order.</p>
          ) : (
            items.map((item) => (
              <div key={item.id} className="cart-line-item">
                <div>
                  <p className="cart-line-title">{item.name}</p>
                  <p className="cart-line-price">${item.price}</p>
                </div>
                <div className="cart-line-controls">
                  <button type="button" onClick={() => onQty(item.id, Math.max(1, item.qty - 1))}>-</button>
                  <span>{item.qty}</span>
                  <button type="button" onClick={() => onQty(item.id, item.qty + 1)}>+</button>
                </div>
                <button type="button" className="cart-remove-btn" onClick={() => onRemove(item.id)}>
                  Remove
                </button>
              </div>
            ))
          )}
        </div>
        <div className="cart-drawer-footer">
          <div className="cart-total-row">
            <span>Total</span>
            <strong>${total}</strong>
          </div>
          <button type="button" className="collection-primary-btn cart-checkout-btn">
            Checkout
          </button>
        </div>
      </aside>
    </>
  );
}

export default function CollectionPage({
  onBackHome,
  onOpenCustomizer,
  cartItems,
  onAddToCart,
  onUpdateCartQty,
  onRemoveFromCart,
}) {
  const featured = PRODUCTS.find((product) => product.featured) || PRODUCTS[0];
  const rest = PRODUCTS.filter((product) => product.id !== featured.id);
  const [cartOpen, setCartOpen] = React.useState(false);
  const cartCount = cartItems.reduce((sum, item) => sum + item.qty, 0);

  return (
    <div className="collection-shell">
      <header className="collection-nav">
        <div className="collection-branding">
          <p className="collection-kicker">YB PRINTING CO.</p>
          <h1>Objects for sale, designed to turn attention into orders.</h1>
        </div>
        <div className="collection-nav-actions">
          <button type="button" className="home-nav-link" onClick={onBackHome}>Home</button>
          <button type="button" className="home-nav-link" onClick={onOpenCustomizer}>Builder</button>
          <button type="button" className="collection-cart-btn" onClick={() => setCartOpen(true)}>
            Cart ({cartCount})
          </button>
        </div>
      </header>

      <section className="collection-hero">
        <div className="collection-hero-copy">
          <p className="collection-section-label">§ 01 / Featured Object</p>
          <h2>{featured.name}</h2>
          <p>{featured.description}</p>
          <div className="collection-hero-actions">
            <button type="button" className="collection-primary-btn" onClick={() => onAddToCart(featured)}>
              Add featured item
            </button>
            <button type="button" className="collection-secondary-btn" onClick={onOpenCustomizer}>
              Open custom builder
            </button>
          </div>
        </div>
        <div className="collection-hero-visual" style={{ background: featured.color }}>
          <div className="collection-hero-garment" style={{ color: featured.accent }}>
            <span>PT</span>
          </div>
          <div className="collection-hero-meta">
            <span>{featured.tagline}</span>
            <strong>${featured.price}</strong>
          </div>
        </div>
      </section>

      <MarqueeRow items={MARQUEE_TOP} />

      <section className="collection-manifesto">
        <div>
          <p className="collection-section-label">§ 02 / Manifesto</p>
        </div>
        <div>
          <p className="collection-manifesto-copy">
            A collection page should not feel flat. Each piece should carry weight, mood, and commercial clarity. This release turns branded apparel into a sellable system with a featured object, a working grid, and a path into customization.
          </p>
        </div>
      </section>

      <section className="collection-grid-section">
        <div className="collection-grid-header">
          <div>
            <p className="collection-section-label">§ 03 / Collection</p>
            <h2>The Collection.</h2>
          </div>
          <p>
            {PRODUCTS.length} sellable objects. Add straight to cart or jump into the builder when the customer needs branded customization.
          </p>
        </div>

        <div className="collection-grid">
          {rest.map((product) => (
            <ProductCard
              key={product.id}
              product={product}
              onAddToCart={onAddToCart}
              onOpenCustomizer={onOpenCustomizer}
            />
          ))}
        </div>
      </section>

      <section className="collection-feature-block">
        <div>
          <p className="collection-section-label collection-section-label-inverse">§ 04 / Motion</p>
          <h2>Rotation still leads the story.</h2>
          <p>
            The builder remains the deep-detail environment. The collection page handles discovery and sales; the customizer handles the final branded garment.
          </p>
        </div>
        <div className="collection-feature-visual-wrap">
          <div className="collection-feature-visual">
            <div className="collection-feature-orbit" />
            <div className="collection-hero-garment feature" style={{ color: featured.accent, background: featured.color }}>
              <span>PT</span>
            </div>
          </div>
        </div>
      </section>

      <MarqueeRow items={MARQUEE_BOTTOM} />

      <footer className="collection-footer">
        <p>YB Printing Co.</p>
        <p>Collection, branding, packaging, print, and custom apparel.</p>
      </footer>

      <CartDrawer
        open={cartOpen}
        items={cartItems}
        onClose={() => setCartOpen(false)}
        onQty={onUpdateCartQty}
        onRemove={onRemoveFromCart}
      />
    </div>
  );
}
