import React, { useState } from 'react';
import ShirtViewer from './ShirtViewer.jsx';
import LogoUploader from './LogoUploader.jsx';
import Controls from './Controls.jsx';
import ImageProcessor from './ImageProcessor.jsx';
import { GARMENTS, getGarment } from '../garments.js';

export default function CustomizerPage({
  shirtColor,
  setShirtColor,
  backgroundColor,
  setBackgroundColor,
  autoRotate,
  setAutoRotate,
  selectedSize,
  setSelectedSize,
  frontLogoUrl,
  setFrontLogoUrl,
  backLogoUrl,
  setBackLogoUrl,
  activeLogoSide,
  setActiveLogoSide,
  logoSettings,
  setLogoSettings,
  logoCount,
  onBackHome,
  onOpenCollection,
  onAddToCart,
}) {
  const [mobileTab, setMobileTab] = useState('preview');
  const [garmentId, setGarmentId] = useState('tshirt');
  const [activeViewerPanel, setActiveViewerPanel] = useState(null); // 'size' | 'rotation'
  const [pendingFile, setPendingFile] = useState(null);
  const [pendingLogoSide, setPendingLogoSide] = useState('front');

  const garment = getGarment(garmentId);
  const hasActiveLogo = activeLogoSide === 'front' ? !!frontLogoUrl : !!backLogoUrl;

  const handleGarmentChange = (id) => {
    const g = getGarment(id);
    setGarmentId(id);
    // Reset logo positions to new garment defaults
    setLogoSettings({
      front: { ...g.logoDefaults.front },
      back: { ...g.logoDefaults.back },
    });
    setActiveViewerPanel(null);
  };

  const handleRawFileSelected = (file, side) => {
    setPendingLogoSide(side);
    setPendingFile(file);
  };

  const handleImageApply = (dataUrl) => {
    if (pendingLogoSide === 'front') {
      if (frontLogoUrl && frontLogoUrl.startsWith('blob:')) URL.revokeObjectURL(frontLogoUrl);
      setFrontLogoUrl(dataUrl);
    } else {
      if (backLogoUrl && backLogoUrl.startsWith('blob:')) URL.revokeObjectURL(backLogoUrl);
      setBackLogoUrl(dataUrl);
    }
    setPendingFile(null);
  };

  const toggleViewerPanel = (panel) => {
    setActiveViewerPanel((prev) => (prev === panel ? null : panel));
  };

  const updateActiveLogo = (key, value) => {
    setLogoSettings((prev) => ({
      ...prev,
      [activeLogoSide]: { ...prev[activeLogoSide], [key]: value },
    }));
  };

  return (
    <div className="app">
      <header className="navbar">
        <div className="navbar-content">
          <div className="logo">
            <span className="logo-text">YB PRINTING CO.</span>
          </div>
          <nav className="nav-links">
            <button type="button" className="nav-text-btn" onClick={onBackHome}>HOME</button>
            <button type="button" className="nav-text-btn" onClick={onOpenCollection}>COLLECTION</button>
          </nav>
          <div className="nav-actions">
            <button className="icon-btn" type="button" aria-label="Back to home" onClick={onBackHome}>
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <path d="m15 18-6-6 6-6"/>
              </svg>
            </button>
          </div>
        </div>
      </header>

      {/* Garment selector — full-width strip */}
      <div className="garment-selector-bar">
        {GARMENTS.map((g) => (
          <button
            key={g.id}
            type="button"
            className={`garment-btn${garmentId === g.id ? ' active' : ''}`}
            onClick={() => handleGarmentChange(g.id)}
          >
            <span className="garment-icon" aria-hidden="true">
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
                <path d="M7 4h10l2 4-2 2v10H7V10L5 8l2-4z" />
                <path d="M9 4c0 1.5 1.3 2.5 3 2.5s3-1 3-2.5" />
              </svg>
            </span>
            <span className="garment-label">{g.label}</span>
          </button>
        ))}
      </div>

      <main className="product-page">
        {/* Mobile tab bar */}
        <div className="mobile-tab-bar">
          <button
            type="button"
            className={`mobile-tab-btn${mobileTab === 'preview' ? ' active' : ''}`}
            onClick={() => setMobileTab('preview')}
          >3D Preview</button>
          <button
            type="button"
            className={`mobile-tab-btn${mobileTab === 'customize' ? ' active' : ''}`}
            onClick={() => setMobileTab('customize')}
          >Customize</button>
        </div>

        <section className={`viewer-section${mobileTab === 'customize' ? ' mobile-hidden' : ''}`}>
          <div className="viewer-wrapper" style={{ backgroundColor }}>
            <ShirtViewer
              garment={garment}
              shirtColor={shirtColor}
              backgroundColor={backgroundColor}
              frontLogoUrl={frontLogoUrl}
              backLogoUrl={backLogoUrl}
              logoSettings={logoSettings}
              setLogoSettings={setLogoSettings}
              activeLogoSide={activeLogoSide}
              setActiveLogoSide={setActiveLogoSide}
              enableAutoRotate={autoRotate}
            />

            {/* Quick-access overlay controls for logo size / rotation */}
            {hasActiveLogo && (
              <div className="viewer-logo-controls">
                <button
                  type="button"
                  className={`viewer-ctrl-btn${activeViewerPanel === 'size' ? ' active' : ''}`}
                  onClick={() => toggleViewerPanel('size')}
                >
                  <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                    <path d="M21 21H3M21 3v18M3 3l18 18"/>
                  </svg>
                  SIZE
                </button>
                <button
                  type="button"
                  className={`viewer-ctrl-btn${activeViewerPanel === 'rotation' ? ' active' : ''}`}
                  onClick={() => toggleViewerPanel('rotation')}
                >
                  <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                    <path d="M21.5 2v6h-6M2.5 22v-6h6M2 11.5a10 10 0 0 1 18.8-4.3M22 12.5a10 10 0 0 1-18.8 4.2"/>
                  </svg>
                  ROTATE
                </button>

                {activeViewerPanel && (
                  <div className="viewer-slider-popup">
                    <div className="viewer-slider-label">
                      {activeViewerPanel === 'size'
                        ? `Size: ${logoSettings[activeLogoSide].scale.toFixed(2)}`
                        : `Rotation: ${(logoSettings[activeLogoSide].rotation * (180 / Math.PI)).toFixed(0)}°`}
                    </div>
                    <input
                      type="range"
                      className="viewer-slider-range"
                      min={activeViewerPanel === 'size' ? '0.05' : String(-Math.PI)}
                      max={activeViewerPanel === 'size' ? '1.0' : String(Math.PI)}
                      step={activeViewerPanel === 'size' ? '0.01' : '0.05'}
                      value={activeViewerPanel === 'size'
                        ? logoSettings[activeLogoSide].scale
                        : logoSettings[activeLogoSide].rotation}
                      onChange={(e) => {
                        const val = parseFloat(e.target.value);
                        updateActiveLogo(activeViewerPanel === 'size' ? 'scale' : 'rotation', val);
                      }}
                    />
                  </div>
                )}
              </div>
            )}

            <button
              className="view-360-badge"
              onClick={() => setAutoRotate(!autoRotate)}
            >
              {autoRotate ? (
                <>
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
                    <rect x="6" y="4" width="4" height="16" rx="1"/>
                    <rect x="14" y="4" width="4" height="16" rx="1"/>
                  </svg>
                  <span>PAUSE</span>
                </>
              ) : (
                <>
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                    <path d="M21.5 2v6h-6M2.5 22v-6h6M2 11.5a10 10 0 0 1 18.8-4.3M22 12.5a10 10 0 0 1-18.8 4.2"/>
                  </svg>
                  <span>360° VIEW</span>
                </>
              )}
            </button>
          </div>
          <div className="interaction-hint">
            Drag to rotate · Scroll to zoom · Drag logo to reposition
          </div>
        </section>

        <section className={`details-section${mobileTab === 'preview' ? ' mobile-hidden' : ''}`}>
          <div className="product-header">
            <div className="breadcrumb">HOME / PRINTING SERVICES / {garment.label.toUpperCase()}</div>
            <h1 className="product-title">{garment.productName}</h1>
            <div className="product-price">
              <span className="price">${garment.price}.00</span>
              <span className="price-note">Free shipping on orders over $100</span>
            </div>
          </div>

          <div className="option-group">
            <LogoUploader
              title="Front Logo"
              setLogo={setFrontLogoUrl}
              currentLogo={frontLogoUrl}
              onFileSelected={(file) => handleRawFileSelected(file, 'front')}
            />
            <LogoUploader
              title="Back Logo"
              setLogo={setBackLogoUrl}
              currentLogo={backLogoUrl}
              onFileSelected={(file) => handleRawFileSelected(file, 'back')}
            />
          </div>

          <Controls
            shirtColor={shirtColor}
            setShirtColor={setShirtColor}
            backgroundColor={backgroundColor}
            setBackgroundColor={setBackgroundColor}
            autoRotate={autoRotate}
            setAutoRotate={setAutoRotate}
            selectedSize={selectedSize}
            setSelectedSize={setSelectedSize}
            activeLogoSide={activeLogoSide}
            setActiveLogoSide={setActiveLogoSide}
            logoSettings={logoSettings}
            setLogoSettings={setLogoSettings}
            logoCount={logoCount}
            hasFrontLogo={!!frontLogoUrl}
            hasBackLogo={!!backLogoUrl}
          />

          <div className="action-buttons">
            <button
              className="btn btn-primary"
              onClick={() => onAddToCart({ id: `custom-${garmentId}`, name: garment.productName, price: garment.price })}
            >
              ADD TO CART
            </button>
            <button className="btn btn-secondary" aria-label="Add to Wishlist">
              <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/>
              </svg>
            </button>
          </div>

          <div className="product-info">
            <div className="info-accordion">
              <details open>
                <summary>Product Details</summary>
                <div className="info-content">
                  <ul>
                    <li>Professional quality print</li>
                    <li>Durable, vibrant colours</li>
                    <li>Custom logo placement — front &amp; back</li>
                    <li>Machine washable (apparel)</li>
                    <li>Ships within 5–7 business days</li>
                  </ul>
                </div>
              </details>
              <details>
                <summary>Shipping &amp; Returns</summary>
                <div className="info-content">
                  <p><strong>Shipping:</strong> Free standard shipping on orders over $100. Express available.</p>
                  <p><strong>Returns:</strong> 30-day return policy. Items must be unmodified with tags attached.</p>
                </div>
              </details>
              <details>
                <summary>Care Instructions</summary>
                <div className="info-content">
                  <p>Machine wash cold with like colours. Tumble dry low. Do not bleach. Cool iron if needed.</p>
                </div>
              </details>
            </div>
          </div>
        </section>
      </main>

      {/* Image processor modal */}
      {pendingFile && (
        <ImageProcessor
          file={pendingFile}
          onApply={handleImageApply}
          onClose={() => setPendingFile(null)}
        />
      )}
    </div>
  );
}
