import React, { Suspense, useEffect, useMemo, useRef, useState } from 'react';
import { Canvas, useThree } from '@react-three/fiber';
import { OrbitControls, Environment, useGLTF, ContactShadows, useProgress } from '@react-three/drei';
import * as THREE from 'three';
import { GARMENTS } from '../garments.js';

function CameraUpdater({ position, fov }) {
  const { camera } = useThree();
  useEffect(() => {
    camera.position.set(...position);
    camera.fov = fov;
    camera.updateProjectionMatrix();
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [position[0], position[1], position[2], fov]);
  return null;
}

function clamp(value, min, max) {
  return Math.min(Math.max(value, min), max);
}

function GarmentMeshes({
  garmentPath,
  groupPosition,
  groupScale = [1, 1, 1],
  logoBounds,
  color = '#ffffff',
  frontLogoUrl = null,
  backLogoUrl = null,
  logoSettings,
  setLogoSettings,
  activeLogoSide,
  setActiveLogoSide,
  isDragging = false,
  setIsDragging,
}) {
  const { scene } = useGLTF(garmentPath);
  const [frontLogoTexture, setFrontLogoTexture] = useState(null);
  const [backLogoTexture, setBackLogoTexture] = useState(null);
  const groupRef = useRef(null);

  const clonedScene = useMemo(() => scene.clone(true), [scene]);

  const garmentMaterial = useMemo(
    () =>
      new THREE.MeshStandardMaterial({
        color,
        roughness: 0.9,
        metalness: 0,
        envMapIntensity: 0.6,
        side: THREE.DoubleSide,
      }),
    [color],
  );

  useEffect(() => {
    clonedScene.traverse((child) => {
      if (child.isMesh) {
        child.material = garmentMaterial;
        child.castShadow = true;
        child.receiveShadow = true;
      }
    });
  }, [clonedScene, garmentMaterial]);

  useEffect(() => {
    const loader = new THREE.TextureLoader();
    const loadTexture = (url, setter) => {
      if (!url) { setter(null); return; }
      loader.load(
        url,
        (tex) => {
          tex.flipY = true;
          tex.colorSpace = THREE.SRGBColorSpace;
          tex.wrapS = THREE.ClampToEdgeWrapping;
          tex.wrapT = THREE.ClampToEdgeWrapping;
          tex.anisotropy = 16;
          tex.needsUpdate = true;
          setter(tex);
        },
        undefined,
        () => setter(null),
      );
    };
    loadTexture(frontLogoUrl, setFrontLogoTexture);
    loadTexture(backLogoUrl, setBackLogoTexture);
  }, [frontLogoUrl, backLogoUrl]);

  const updateLogoPosition = (side, point) => {
    setLogoSettings((prev) => ({
      ...prev,
      [side]: {
        ...prev[side],
        position: {
          x: clamp(point.x, logoBounds.x.min, logoBounds.x.max),
          y: clamp(point.y, logoBounds.y.min, logoBounds.y.max),
          z: clamp(point.z, logoBounds.z[side].min, logoBounds.z[side].max),
        },
      },
    }));
  };

  const handleLogoPointerDown = (side) => (event) => {
    const tex = side === 'front' ? frontLogoTexture : backLogoTexture;
    if (!tex) return;
    event.stopPropagation();
    event.target.setPointerCapture?.(event.pointerId);
    setActiveLogoSide(side);
    setIsDragging(true);
  };

  const handleLogoPointerMove = (side) => (event) => {
    if (!isDragging || !groupRef.current) return;
    event.stopPropagation();
    const logoPos = logoSettings[side].position;
    const dragPlane = new THREE.Plane(new THREE.Vector3(0, 0, 1), -logoPos.z);
    const intersection = new THREE.Vector3();
    if (!event.ray.intersectPlane(dragPlane, intersection)) return;
    const local = groupRef.current.worldToLocal(intersection.clone());
    updateLogoPosition(side, { x: local.x, y: local.y, z: logoPos.z });
  };

  const handleLogoPointerUp = (event) => {
    event.stopPropagation();
    event.target.releasePointerCapture?.(event.pointerId);
    setIsDragging(false);
  };

  return (
    <group ref={groupRef} position={groupPosition} scale={groupScale}>
      <primitive object={clonedScene} />
      {frontLogoTexture && (
        <mesh
          position={[logoSettings.front.position.x, logoSettings.front.position.y, logoSettings.front.position.z]}
          rotation={[0, 0, logoSettings.front.rotation]}
          renderOrder={10}
          onPointerDown={handleLogoPointerDown('front')}
          onPointerMove={handleLogoPointerMove('front')}
          onPointerUp={handleLogoPointerUp}
          onPointerOut={handleLogoPointerUp}
        >
          <planeGeometry args={[logoSettings.front.scale, logoSettings.front.scale]} />
          <meshBasicMaterial map={frontLogoTexture} transparent alphaTest={0.01}
            depthTest={false} depthWrite={false} polygonOffset polygonOffsetFactor={-2}
            toneMapped={false} side={THREE.FrontSide} />
        </mesh>
      )}
      {backLogoTexture && (
        <mesh
          position={[logoSettings.back.position.x, logoSettings.back.position.y, logoSettings.back.position.z]}
          rotation={[0, Math.PI, -logoSettings.back.rotation]}
          renderOrder={10}
          onPointerDown={handleLogoPointerDown('back')}
          onPointerMove={handleLogoPointerMove('back')}
          onPointerUp={handleLogoPointerUp}
          onPointerOut={handleLogoPointerUp}
        >
          <planeGeometry args={[logoSettings.back.scale, logoSettings.back.scale]} />
          <meshBasicMaterial map={backLogoTexture} transparent alphaTest={0.01}
            depthTest={false} depthWrite={false} polygonOffset polygonOffsetFactor={-2}
            toneMapped={false} side={THREE.FrontSide} />
        </mesh>
      )}
    </group>
  );
}

function ViewerLoader({ backgroundColor = '#000000' }) {
  const { active, progress } = useProgress();
  if (!active && progress >= 100) return null;
  return (
    <div className="viewer-loading-overlay" style={{ backgroundColor }} aria-live="polite" aria-busy="true">
      <div className="viewer-loading-mark">
        <div className="viewer-loading-ring" />
        <div className="viewer-loading-brand">YB PRINTING CO.</div>
        <div className="viewer-loading-copy">Preparing your 3D preview</div>
        <div className="viewer-loading-progress">{Math.round(progress)}%</div>
      </div>
    </div>
  );
}

function Scene({
  garment,
  shirtColor = '#ffffff',
  backgroundColor = '#000000',
  frontLogoUrl = null,
  backLogoUrl = null,
  logoSettings,
  setLogoSettings,
  activeLogoSide,
  setActiveLogoSide,
  enableAutoRotate = false,
  isDragging,
  setIsDragging,
}) {
  return (
    <>
      <color attach="background" args={[backgroundColor]} />
      <CameraUpdater position={garment.camera.position} fov={garment.camera.fov} />
      <ambientLight intensity={0.7} />
      <directionalLight position={[3, 5, 3]} intensity={1.8} castShadow
        shadow-mapSize-width={1024} shadow-mapSize-height={1024}
        shadow-camera-far={20} shadow-camera-left={-5} shadow-camera-right={5}
        shadow-camera-top={5} shadow-camera-bottom={-5} />
      <directionalLight position={[-3, 3, -3]} intensity={0.5} color="#b8d4ff" />
      <hemisphereLight intensity={0.8} color="#ffffff" groundColor={backgroundColor} />
      <Suspense fallback={null}>
        <GarmentMeshes
          garmentPath={garment.path}
          groupPosition={garment.groupPosition}
          groupScale={garment.groupScale || [1, 1, 1]}
          logoBounds={garment.logoBounds}
          color={shirtColor}
          frontLogoUrl={frontLogoUrl}
          backLogoUrl={backLogoUrl}
          logoSettings={logoSettings}
          setLogoSettings={setLogoSettings}
          activeLogoSide={activeLogoSide}
          setActiveLogoSide={setActiveLogoSide}
          isDragging={isDragging}
          setIsDragging={setIsDragging}
        />
        <Environment preset="studio" />
      </Suspense>
      <ContactShadows
        position={[0, garment.shadowY ?? (garment.groupPosition[1] + 0.05), 0]}
        opacity={0.1} scale={4.1} blur={2} far={4} color={backgroundColor}
      />
      <OrbitControls
        makeDefault
        enabled={!isDragging}
        enablePan={false} enableZoom enableDamping dampingFactor={0.08}
        minDistance={garment.minDistance} maxDistance={garment.maxDistance}
        target={garment.orbitTarget}
        minPolarAngle={garment.minPolar} maxPolarAngle={garment.maxPolar}
        autoRotate={enableAutoRotate} autoRotateSpeed={1.5}
      />
    </>
  );
}

export default function ShirtViewer({
  garment,
  shirtColor = '#ffffff',
  backgroundColor = '#000000',
  frontLogoUrl = null,
  backLogoUrl = null,
  logoSettings,
  setLogoSettings,
  activeLogoSide,
  setActiveLogoSide,
  enableAutoRotate = false,
}) {
  const [isDragging, setIsDragging] = useState(false);
  const { active, progress } = useProgress();
  const isLoading = active || progress < 100;

  return (
    <div style={{ width: '100%', height: '100%', position: 'relative' }}>
      {isLoading && <ViewerLoader backgroundColor={backgroundColor} />}
      <Canvas
        key={garment.id}
        frameloop="always"
        shadows
        dpr={[1, 2]}
        style={{ opacity: isLoading ? 0 : 1, transition: 'opacity 0.25s ease', touchAction: 'none' }}
        camera={{ position: garment.camera.position, fov: garment.camera.fov, near: 0.1, far: 1000 }}
        gl={{ antialias: true, alpha: false, powerPreference: 'default', failIfMajorPerformanceCaveat: false, preserveDrawingBuffer: false }}
      >
        <Scene
          garment={garment}
          shirtColor={shirtColor}
          backgroundColor={backgroundColor}
          frontLogoUrl={frontLogoUrl}
          backLogoUrl={backLogoUrl}
          logoSettings={logoSettings}
          setLogoSettings={setLogoSettings}
          activeLogoSide={activeLogoSide}
          setActiveLogoSide={setActiveLogoSide}
          enableAutoRotate={enableAutoRotate}
          isDragging={isDragging}
          setIsDragging={setIsDragging}
        />
      </Canvas>
    </div>
  );
}

GARMENTS.forEach((g) => useGLTF.preload(g.path));
