import React, { useCallback, useEffect, useRef, useState } from 'react';

function colorDistance(r1, g1, b1, r2, g2, b2) {
  return Math.sqrt((r1 - r2) ** 2 + (g1 - g2) ** 2 + (b1 - b2) ** 2);
}

export default function ImageProcessor({ file, onApply, onClose }) {
  const canvasRef = useRef(null);
  const originalDataRef = useRef(null);
  const [tolerance, setTolerance] = useState(40);
  const [bgRemoved, setBgRemoved] = useState(false);

  useEffect(() => {
    if (!file) return;
    const url = URL.createObjectURL(file);
    const img = new Image();
    img.onload = () => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      canvas.width = img.naturalWidth;
      canvas.height = img.naturalHeight;
      const ctx = canvas.getContext('2d');
      ctx.drawImage(img, 0, 0);
      originalDataRef.current = ctx.getImageData(0, 0, canvas.width, canvas.height);
      URL.revokeObjectURL(url);
    };
    img.src = url;
    return () => URL.revokeObjectURL(url);
  }, [file]);

  const removeBackground = useCallback(() => {
    const canvas = canvasRef.current;
    if (!canvas || !originalDataRef.current) return;
    const ctx = canvas.getContext('2d');
    const imageData = new ImageData(
      new Uint8ClampedArray(originalDataRef.current.data),
      canvas.width,
      canvas.height,
    );
    const { data, width, height } = imageData;

    // Sample all 4 corners and use the most common background color
    const corners = [
      [data[0], data[1], data[2]],
      [data[(width - 1) * 4], data[(width - 1) * 4 + 1], data[(width - 1) * 4 + 2]],
      [data[(height - 1) * width * 4], data[(height - 1) * width * 4 + 1], data[(height - 1) * width * 4 + 2]],
      [data[((height - 1) * width + width - 1) * 4], data[((height - 1) * width + width - 1) * 4 + 1], data[((height - 1) * width + width - 1) * 4 + 2]],
    ];
    // Average corner colors as background reference
    const [bgR, bgG, bgB] = corners.reduce(
      (acc, c) => [acc[0] + c[0] / 4, acc[1] + c[1] / 4, acc[2] + c[2] / 4],
      [0, 0, 0],
    );

    for (let i = 0; i < data.length; i += 4) {
      const dist = colorDistance(data[i], data[i + 1], data[i + 2], bgR, bgG, bgB);
      if (dist <= tolerance) {
        data[i + 3] = 0;
      }
    }
    ctx.putImageData(imageData, 0, 0);
    setBgRemoved(true);
  }, [tolerance]);

  const resetImage = () => {
    const canvas = canvasRef.current;
    if (!canvas || !originalDataRef.current) return;
    const ctx = canvas.getContext('2d');
    ctx.putImageData(originalDataRef.current, 0, 0);
    setBgRemoved(false);
  };

  const handleApply = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    onApply(canvas.toDataURL('image/png'));
  };

  const handleOverlayClick = (e) => {
    if (e.target === e.currentTarget) onClose();
  };

  return (
    <div className="imgp-overlay" onClick={handleOverlayClick}>
      <div className="imgp-modal">
        <div className="imgp-header">
          <h2>Image Editor</h2>
          <button className="imgp-close" onClick={onClose} aria-label="Close">
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
              <path d="M18 6 6 18M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div className="imgp-body">
          <div className="imgp-canvas-wrap">
            <canvas ref={canvasRef} className="imgp-canvas" />
          </div>

          <div className="imgp-controls">
            <div className="imgp-section">
              <h3>Remove Background</h3>
              <p className="imgp-hint">
                Removes pixels matching the background colour (sampled from image corners).
                Works best on logos with solid or near-solid backgrounds.
              </p>

              <label className="imgp-tol-label">
                Tolerance: <strong>{tolerance}</strong>
              </label>
              <input
                type="range"
                className="imgp-range"
                min="0"
                max="120"
                value={tolerance}
                onChange={(e) => setTolerance(Number(e.target.value))}
              />

              <div className="imgp-btn-row">
                <button className="imgp-btn imgp-btn-primary" onClick={removeBackground}>
                  Remove Background
                </button>
                {bgRemoved && (
                  <button className="imgp-btn imgp-btn-ghost" onClick={resetImage}>
                    Reset
                  </button>
                )}
              </div>
            </div>

            <div className="imgp-footer">
              <button className="imgp-btn imgp-btn-ghost" onClick={onClose}>
                Cancel
              </button>
              <button className="imgp-btn imgp-btn-apply" onClick={handleApply}>
                Use This Image →
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
