import React, { useState } from 'react';
import LandingPage from './src/components/LandingPage.jsx';
import CustomizerPage from './src/components/CustomizerPage.jsx';
import CollectionPage from './src/components/CollectionPage.jsx';
import './App.css';

function App() {
  const [currentPage, setCurrentPage] = useState('home');
  const [cartItems, setCartItems] = useState([]);
  const [shirtColor, setShirtColor] = useState('#ffffff');
  const [backgroundColor, setBackgroundColor] = useState('#000000');
  const [autoRotate, setAutoRotate] = useState(true);
  const [selectedSize, setSelectedSize] = useState('M');
  const [frontLogoUrl, setFrontLogoUrl] = useState(null);
  const [backLogoUrl, setBackLogoUrl] = useState(null);
  const [activeLogoSide, setActiveLogoSide] = useState('front');
  const [logoSettings, setLogoSettings] = useState({
    front: {
      position: { x: 0.015230818837193738, y: 1.4088348413144813, z: 0.11 },
      scale: 0.35,
      rotation: 0,
    },
    back: {
      position: { x: 0.015230818837193738, y: 1.4088348413144813, z: -0.11 },
      scale: 0.35,
      rotation: 0,
    },
  });

  const logoCount = Number(Boolean(frontLogoUrl)) + Number(Boolean(backLogoUrl));

  const handleAddToCart = (product) => {
    setCartItems((prev) => {
      const existing = prev.find((item) => item.id === product.id);

      if (existing) {
        return prev.map((item) => (
          item.id === product.id ? { ...item, qty: item.qty + 1 } : item
        ));
      }

      return [...prev, { ...product, qty: 1 }];
    });
  };

  const handleUpdateCartQty = (productId, qty) => {
    setCartItems((prev) => prev.map((item) => (
      item.id === productId ? { ...item, qty } : item
    )));
  };

  const handleRemoveFromCart = (productId) => {
    setCartItems((prev) => prev.filter((item) => item.id !== productId));
  };

  if (currentPage === 'home') {
    return (
      <LandingPage
        onOpenCustomizer={() => setCurrentPage('customizer')}
        onOpenCollection={() => setCurrentPage('collection')}
      />
    );
  }

  if (currentPage === 'collection') {
    return (
      <CollectionPage
        onBackHome={() => setCurrentPage('home')}
        onOpenCustomizer={() => setCurrentPage('customizer')}
        cartItems={cartItems}
        onAddToCart={handleAddToCart}
        onUpdateCartQty={handleUpdateCartQty}
        onRemoveFromCart={handleRemoveFromCart}
      />
    );
  }

  return (
    <CustomizerPage
      shirtColor={shirtColor}
      setShirtColor={setShirtColor}
      backgroundColor={backgroundColor}
      setBackgroundColor={setBackgroundColor}
      autoRotate={autoRotate}
      setAutoRotate={setAutoRotate}
      selectedSize={selectedSize}
      setSelectedSize={setSelectedSize}
      frontLogoUrl={frontLogoUrl}
      setFrontLogoUrl={setFrontLogoUrl}
      backLogoUrl={backLogoUrl}
      setBackLogoUrl={setBackLogoUrl}
      activeLogoSide={activeLogoSide}
      setActiveLogoSide={setActiveLogoSide}
      logoSettings={logoSettings}
      setLogoSettings={setLogoSettings}
      logoCount={logoCount}
      onBackHome={() => setCurrentPage('home')}
      onOpenCollection={() => setCurrentPage('collection')}
      onAddToCart={handleAddToCart}
    />
  );
}

export default App;
