import React, { useState } from 'react';

const OLLAMA_MODEL = 'llama3';
const OLLAMA_URL = 'http://localhost:11434/api/chat';

const SYSTEM_PROMPT = `You are Studio Guide, the project concierge for YB Printing Co., a brand, packaging, print, and apparel studio.

When the user sends a message, respond with ONLY a valid JSON object in this exact format:
{"reply":"<your response>","route":"<customizer|collection|section|none>","section":"<brand|package|clothing|printing>"}

Route rules:
- "customizer" -> user wants branded clothing, shirts, t-shirts, uniforms, hoodies, merch, apparel, jerseys
- "collection" -> user wants to shop, browse, buy, see products, catalog, store
- "section" with section "brand" -> branding, logo, visual identity, brand kit, rebrand
- "section" with section "package" -> packaging, boxes, mailers, inserts, product packaging, bundle set
- "section" with section "printing" -> print materials: flyers, cards, banners, posters, stickers, signage, menu cards, floor wraps, stationery
- "none" -> anything else; explain we cover brand building, packaging, branded clothing, and printing only

Keep replies warm, direct, and under two sentences. Omit "section" key when route is not "section".`;

const INTRO_MESSAGE = 'Choose one quote path and I will route it for you.';

const QUICK_OPTIONS = [
  {
    key: 'stationery',
    number: '01',
    title: 'Request quote for Stationery',
    description: 'Business cards, letterhead, envelopes, flyers, menus, and other print collateral.',
    actionLabel: 'Start quote',
    prompt: 'I need a quote for stationery printing.',
  },
  {
    key: 'custom-tshirt',
    number: '02',
    title: 'Start your custom T-shirt order',
    description: 'Branded shirts, uniforms, hoodies, merch, and apparel for teams or events.',
    actionLabel: 'Open builder',
    prompt: 'I need a quote for a custom t-shirt.',
  },
  {
    key: 'branding-design',
    number: '03',
    title: 'Request quote for Branding Design',
    description: 'Logo direction, visual identity, launch-ready design systems, and brand refreshes.',
    actionLabel: 'Start quote',
    prompt: 'I need a quote for branding design.',
  },
];

const SUGGESTIONS = [
  'Need a stationery quote for my business',
  'Custom t-shirts for an event',
  'Branding design for a new company',
];

async function askLlama(history) {
  const messages = [
    { role: 'system', content: SYSTEM_PROMPT },
    ...history.map((m) => ({ role: m.role === 'assistant' ? 'assistant' : 'user', content: m.content })),
  ];

  const res = await fetch(OLLAMA_URL, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ model: OLLAMA_MODEL, messages, stream: false }),
    signal: AbortSignal.timeout(15000),
  });

  if (!res.ok) throw new Error(`Ollama ${res.status}`);

  const data = await res.json();
  const raw = data?.message?.content ?? '';
  const parsed = JSON.parse(raw.replace(/```[a-z]*\n?/gi, '').trim());

  return {
    reply: parsed.reply ?? raw,
    route: parsed.route ?? 'none',
    section: parsed.section ?? null,
  };
}

function detectIntent(prompt) {
  const value = prompt.toLowerCase();

  if (/(shirt|t-shirt|tee|hoodie|uniform|apparel|clothe|clothing|merch|jersey|branded wear)/.test(value)) {
    return {
      reply: 'I am sending you to the builder for your custom t-shirt quote.',
      route: 'customizer',
    };
  }

  if (/(stationery|business card|letterhead|envelope|flyer|menu|brochure|card stock|paper)/.test(value)) {
    return {
      reply: 'Stationery fits our print lane. I am routing that request now.',
      route: 'section',
      section: 'printing',
    };
  }

  if (/(brand|branding|logo system|identity|brand kit|rebrand|design)/.test(value)) {
    return {
      reply: 'Branding design is the right starting point. I highlighted that request below.',
      route: 'section',
      section: 'brand',
    };
  }

  return {
    reply: 'We currently support stationery, custom t-shirts, and branding design.',
    route: 'none',
  };
}

function QuickIcon({ variant }) {
  if (variant === 'custom-tshirt') {
    return (
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
        <path d="M7 4h10l2 4-2 2v10H7V10L5 8l2-4z" />
        <path d="M9 4c0 1.5 1.3 2.5 3 2.5s3-1 3-2.5" />
      </svg>
    );
  }

  if (variant === 'branding-design') {
    return (
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
        <path d="M4 20h16" />
        <path d="M7 16l10-10 3 3-10 10H7v-3z" />
        <path d="M14 6l3 3" />
      </svg>
    );
  }

  return (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
      <rect x="4" y="5" width="16" height="14" rx="2" />
      <path d="M7 9h10M7 13h8" />
    </svg>
  );
}

export default function LandingPage({ onOpenCustomizer, onOpenCollection }) {
  const [inputValue, setInputValue] = useState('');
  const [messages, setMessages] = useState([{ role: 'assistant', content: INTRO_MESSAGE }]);
  const [isThinking, setIsThinking] = useState(false);
  const [isConciergeOpen, setIsConciergeOpen] = useState(false);
  const [activeOption, setActiveOption] = useState('stationery');

  const submitPrompt = async (prompt) => {
    const trimmed = prompt.trim();
    if (!trimmed || isThinking) {
      return;
    }

    const userMessage = { role: 'user', content: trimmed };
    const historyForLlama = [...messages, userMessage];

    setMessages((prev) => [...prev, userMessage]);
    setIsThinking(true);

    let intent;
    try {
      intent = await askLlama(historyForLlama);
    } catch (_err) {
      intent = detectIntent(trimmed);
    }

    setMessages((prev) => [...prev, { role: 'assistant', content: intent.reply }]);
    setIsThinking(false);

    if (intent.route === 'customizer') {
      onOpenCustomizer();
      return;
    }

    if (intent.route === 'collection') {
      onOpenCollection();
    }
  };

  const handleQuickAction = (option) => {
    setActiveOption(option.key);

    if (option.key === 'custom-tshirt') {
      onOpenCustomizer();
      return;
    }

    setIsConciergeOpen(true);
    setInputValue(option.prompt);
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    await submitPrompt(inputValue);
    setInputValue('');
  };

  return (
    <div className="home-shell yb-landing-shell">
      <div className="yb-topbar">
        <div className="yb-topbar-inner">
          <span>High Quality</span>
          <span>On Time Delivery</span>
          <span>Everyday Fair Prices</span>
        </div>
      </div>

      <header className="home-nav yb-nav">
        <div className="home-brand-lockup">
          <span className="home-brand-kicker">YB PRINTING CO.</span>
          <span className="home-brand-name">Choose one quote path to keep the page focused and simple.</span>
        </div>
        <div className="home-nav-actions">
          <button type="button" className="home-nav-link" onClick={() => setIsConciergeOpen(true)}>
            Concierge
          </button>
        </div>
      </header>

      <main className="home-main yb-main">
        <section className="print-section" aria-label="quote options">
          <div className="print-grid quote-grid">
            {QUICK_OPTIONS.map((option) => (
              <article key={option.key} className={`print-card${activeOption === option.key ? ' active' : ''}`}>
                <div className="print-card-top">
                  <span className="print-card-number">{option.number}</span>
                  <span className="print-card-icon">
                    <QuickIcon variant={option.key} />
                  </span>
                </div>
                <h2>{option.title}</h2>
                <p className="print-card-copy">{option.description}</p>
                <button type="button" className="service-card-link" onClick={() => handleQuickAction(option)}>
                  {option.actionLabel}
                </button>
              </article>
            ))}
          </div>
        </section>

        <section className="yb-note-strip">
          <p>Pick one service and we will keep the path short.</p>
        </section>

        <section className="hero-panel yb-hero">
          <div className="hero-copy yb-hero-copy">
            <div className="yb-breadcrumbs">
              <span>Home</span>
              <span>Quote Requests</span>
            </div>
            <p className="hero-kicker">REQUEST A QUOTE</p>
            <p className="hero-description">
              Three options only: stationery, custom t-shirts, or branding design.
            </p>
          </div>
        </section>
      </main>

      <button
        type="button"
        className="concierge-fab"
        aria-label={isConciergeOpen ? 'Close concierge' : 'Open concierge'}
        onClick={() => setIsConciergeOpen((prev) => !prev)}
      >
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
          <path d="M21 12a8.5 8.5 0 0 1-8.5 8.5h-7l2.2-3A8.5 8.5 0 1 1 21 12z" />
          <path d="M8.5 10.5h7M8.5 14h4.5" />
        </svg>
      </button>

      {isConciergeOpen && (
        <aside className="concierge-panel" aria-label="Project concierge">
          <div className="chat-shell-header">
            <span className="chat-shell-label">Project Concierge</span>
            <div className="chat-shell-actions">
              <span className={`chat-shell-state ${isThinking ? 'thinking' : ''}`}>{isThinking ? 'Thinking...' : 'Online'}</span>
              <button
                type="button"
                className="chat-close-btn"
                onClick={() => setIsConciergeOpen(false)}
              >
                Close Chat
              </button>
            </div>
          </div>

          <div className="chat-thread">
            {messages.map((message, index) => (
              <div key={`${message.role}-${index}`} className={`chat-bubble ${message.role}`}>
                <span className="chat-role">{message.role === 'assistant' ? 'Studio Guide' : 'You'}</span>
                <p>{message.content}</p>
              </div>
            ))}
            {isThinking && (
              <div className="chat-bubble assistant">
                <span className="chat-role">Studio Guide</span>
                <p className="concierge-thinking"><span /><span /><span /></p>
              </div>
            )}
          </div>

          <form className="chat-composer" onSubmit={handleSubmit}>
            <textarea
              rows="1"
              value={inputValue}
              onChange={(event) => setInputValue(event.target.value)}
              placeholder="What do you need quoted?"
              disabled={isThinking}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                  e.preventDefault();
                  handleSubmit(e);
                }
              }}
            />
            <button type="submit" disabled={isThinking}>Send</button>
          </form>

          <div className="suggestion-row">
            {SUGGESTIONS.map((suggestion) => (
              <button key={suggestion} type="button" className="suggestion-chip" onClick={() => setInputValue(suggestion)}>
                {suggestion}
              </button>
            ))}
          </div>
        </aside>
      )}
    </div>
  );
}
